import React, { useEffect, useRef } from 'react';
import { Html5Qrcode } from 'html5-qrcode';

const Scanner = ({ onScanSuccess }) => {
  const scannerRef = useRef(null);

  useEffect(() => {
    // 1. Initialize the low-level scanner
    const html5QrCode = new Html5Qrcode("reader");
    scannerRef.current = html5QrCode;

    const config = { fps: 10, qrbox: { width: 250, height: 250 } };

    // 2. Start the camera
    html5QrCode.start(
      { facingMode: "environment" }, // Uses back camera on phone, webcam on laptop
      config,
      (decodedText) => {
        onScanSuccess(decodedText);
      },
      (errorMessage) => {
        // ignore errors
      }
    ).catch((err) => {
      console.error("Unable to start scanning", err);
    });

    // 3. CLEANUP: This is the critical fix
    return () => {
      if (scannerRef.current) {
        scannerRef.current.stop().then(() => {
            scannerRef.current.clear();
            // Force the div to be empty so no double UI stays behind
            document.getElementById("reader").innerHTML = "";
        }).catch(err => console.log("Error stopping scanner", err));
      }
    };
  }, []);

  return (
    <div style={{ margin: '20px auto', maxWidth: '500px' }}>
        <div id="reader" style={{ width: '100%', borderRadius: '10px', overflow: 'hidden' }}></div>
        <p style={{color: '#00d1b2', textAlign: 'center'}}>Aim at a QR Code...</p>
    </div>
  );
};

export default Scanner;
